// 換頁後的位置強制：momentum 事件仍傳給 super（防止 NSScrollView fallback animation），
// 但在 reflectScrolledClipView 強制 clamp 位置到 top/bottom，阻止實際視覺位移。
override func reflectScrolledClipView(_ cView: NSClipView) {
    super.reflectScrolledClipView(cView)

    // 連續捲動模式：通知內容視圖更新可見範圍
    if let continuousView = documentView as? ContinuousScrollContentView {
        continuousView.updateVisibleSlots(for: cView.bounds)
    }

    guard suppressScrollSequenceAfterPageTurn,
          !isEnforcingScrollPosition,
          let docView = documentView else { return }

    let yBounds = yScrollBounds(
        docHeight: docView.frame.height,
        clipHeight: cView.bounds.height,
        insets: contentInsets
    )
    let targetY = suppressScrollAtTop ? yBounds.max : yBounds.min
    let currentY = cView.bounds.origin.y

    if abs(currentY - targetY) > Constants.scrollPositionClampTolerance {
        isEnforcingScrollPosition = true
        cView.setBoundsOrigin(NSPoint(x: cView.bounds.origin.x, y: targetY))
        isEnforcingScrollPosition = false
    }
}

/// 切換圖片後回到頂部（macOS 座標系：maxY = 頂部）
/// 使用 contentInsets 計算正確的最大 Y 位置，避免黑邊
func scrollToTop() {
    guard let docView = documentView else { return }
    let yBounds = yScrollBounds(docHeight: docView.frame.height, clipHeight: contentView.bounds.height, insets: contentInsets)
    let topPoint = NSPoint(x: contentView.bounds.origin.x, y: yBounds.max)

/// 開始 zoom：暫停 slot 回收
func beginZoomSuppression() {
    isZooming = true
}

/// 結束 zoom：恢復 slot 回收，處理延遲的記憶體壓力，清理多餘 slots
func endZoomSuppression(visibleBounds: NSRect) {
    isZooming = false
    // 更新 lastKnownVisibleBounds，確保 deferred pressure 使用最新可視區域
    lastKnownVisibleBounds = visibleBounds
    if let level = pendingPressureLevel {
        pendingPressureLevel = nil
        handleMemoryPressure(level)
        // handleMemoryPressure 內部已呼叫 manageSlotViews，不需重複
    } else {
        updateVisibleSlots(for: visibleBounds)
    }
}

